// Alert when cache hit ratio drops below a threshold.
// Requires minimum token volume (50000) to avoid noisy alerts on low-traffic periods.
// Adjust both the 50000 volume threshold and the 0.30 ratio threshold as needed.
FROM metrics-anthropic_metrics.usage-*
| WHERE anthropic.usage.uncached_input_tokens IS NOT NULL
| STATS uncached = SUM(anthropic.usage.uncached_input_tokens), cached = SUM(anthropic.usage.cached_input_tokens), cache_creation = SUM(anthropic.usage.cache_creation_input_tokens)
| EVAL total_input = uncached + cached + cache_creation
| WHERE total_input > 50000
| EVAL cache_hit_ratio = cached * 1.0 / total_input
| WHERE cache_hit_ratio < 0.30
